// variaveis de nós anteriores
const dados = $json;

function percentOfNumber(part, total) {
  return ((100 * part) / total);
}

function formatNumber(number, minPrecision = 1, maxPrecision = 2) {
  number = number ? number : 0;
  return {number, formatPtBr: number.toLocaleString('pt-br', {
      minimumFractionDigits: minPrecision,
      maximumFractionDigits: maxPrecision
    })
  };
}

function formatTime(seconds) {


    // Round to handle decimal inputs
    seconds = Math.round(Number(seconds));

    // Less than 60 seconds
    if (seconds < 60) {
        return seconds === 1 ? '1 second' : `${seconds}s`;
    }

    // Between 60 seconds and 1 hour (less than 3600 seconds)
    else if (seconds < 3600) {
        const minutes = Math.floor(seconds / 60);
        const remainingSeconds = seconds % 60;

        if (remainingSeconds === 0) {
            return minutes === 1 ? '1 minute' : `${minutes} minutes`;
        } else {
            const minuteStr = `${minutes}m`;
            const secondStr = `${remainingSeconds}s`;
            return `${minuteStr} ${secondStr}`;
        }
    }

    // 1 hour or more
    else {
        const hours = Math.floor(seconds / 3600);
        const remainingMinutes = Math.floor((seconds % 3600) / 60);

        let result = `${hours}h`;

        if (remainingMinutes > 0) {
            const minuteStr = `${remainingMinutes}m`;
            result += ` ${minuteStr}`;
        }

        return result;
    }
}


const objectsIgnore = [
  'bdr_conversation_labels'
  , 'period_action'
  , 'time_stats'
]
const formatToTime = [
  'avg_qualifying_time_seconds'
  , 'agent_avg_response_time'
  , 'agent_avg_response_time_norm'
  , 'agent_avg_first_response_time'
  , 'agent_avg_first_response_time_norm'
  , 'lead_avg_response_time'
  , 'lead_avg_response_time_norm'
  , 'lead_avg_first_response_time'
  , 'lead_avg_first_response_time_norm'

] 

const formatToFloat = [
  'avg_interactions'
  , 'qualified_avg_interactions'
  , 'percent_engaged_of_total_conversations'
  , 'percent_sent_links_of_engaged_leads'
  , 'percent_qualified_leads_of_engaged_leads'
  , 'percent_agent_missed_first_response_of_total_conversations'
  , 'percent_lead_missed_first_response_of_total_conversations'
  , 'percent_total_without_interest_of_engaged_leads'

] 

const formattedMessagesData = {};
for (let key in dados) {
  if (objectsIgnore.includes(key)) {
    formattedMessagesData[key] = dados[key]
    continue
  }

  if (formatToFloat.includes(key)) {
    formattedMessagesData[key] = dados[key] != null 
      ? formatNumber(Number(dados[key]), 1, 2)
      : null;
  } else {
    formattedMessagesData[key] = dados[key] != null 
      ? formatNumber(Number(dados[key]), 0, 0)
      : null;
  }

  if (dados[key] != null 
      && (formatToTime.includes(key)
  )) {     
      formattedMessagesData[key].formatPtBr =
        formatTime(formattedMessagesData[key].number);
  }
}

const bdrLabels = dados.bdr_conversation_labels
const bdrLabelsQualificacao = {
    'baixa qualificacao': 0,
    'media qualificacao': 0,
    'alta qualificacao': 0,
    'sem interesse': 0,
  }
if (bdrLabels != null) {

  for (let i = 0; i < bdrLabels.length; ++i) {
     const labelCountPair = bdrLabels[i]

    const labelNorm = labelCountPair.label.replaceAll("_", " ");

    if (bdrLabelsQualificacao[labelNorm] != null) {
      bdrLabelsQualificacao[labelNorm] = labelCountPair.count;
    } 
  }
}


return {
  ...formattedMessagesData
  , bdrLabelsQualificacao
}
